105	}
106	
107	// ─── SSE stream helpers ───────────────────────────────────────────────────────
108	
109	/**
110	 * Build the human-readable progress message for a session analysis stream event.
111	 * The session analysis handler uses chunk-count information; the prompt-quality
112	 * handler uses a fixed string. Accept a resolver callback so each caller decides.
113	 */
114	type ProgressMessageFn = (progress: { phase: string; currentChunk?: number; totalChunks?: number }) => string;
115	
116	/**
117	 * Options for streamSessionAnalysis.
118	 */
119	interface StreamSessionAnalysisOptions {
120	  /**
121	   * Human-readable telemetry type string (e.g. 'session', 'prompt-quality').
122	   * Used as the `type` field in the analysis_run event.
123	   */
124	  analysisType: string;
125	  /**
126	   * The analysis function to call. Must match the signature of analyzeSession /
127	   * analyzePromptQuality — accepts (session, messages, options?) and returns AnalysisResult.
128	   */
129	  analysisFn: (
130	    session: SessionData,
131	    messages: SQLiteMessageRow[],
132	    options?: AnalysisOptions,
133	  ) => Promise<AnalysisResult>;
134	  /**
135	   * Resolve the progress event message from the current progress state.
136	   * Called inside the onProgress callback to build the human-readable 'message' field.
137	   */
138	  progressMessage: ProgressMessageFn;
139	  /**
140	   * Called on the success path after tracking telemetry (e.g. to apply a generated title
141	   * or emit an insight_generated event). Receives the successful AnalysisResult.
142	   */
143	  onSuccess?: (result: AnalysisResult) => void;
144	}
145	
146	/**
147	 * Shared SSE lifecycle for single-session analysis stream endpoints.
148	 * Handles the streamSSE wrapper, abort signal, progress events, result telemetry,
149	 * and complete/error SSE events. The two analysis stream handlers (session and
150	 * prompt-quality) differed only in their progress message and analysis function —
151	 * those are injected via options.
152	 *
153	 * Preserves the exact SSE event names and complete/error payload shapes the
154	 * dashboard expects: progress → { phase, message, ...progress }, complete →
155	 * { success, insightCount, tokenUsage }, error → { error }.
156	 */
157	export function streamSessionAnalysis(
158	  c: Context,
159	  session: SessionData,
160	  messages: SQLiteMessageRow[],
161	  opts: StreamSessionAnalysisOptions,
162	): ReturnType<typeof streamSSE> {
163	  const llmConfig = loadLLMConfig();
164	
165	  return streamSSE(c, async (stream) => {
166	    const streamStart = Date.now();
167	    try {
168	      const abortSignal = c.req.raw.signal;
169	
170	      await stream.writeSSE({
171	        event: 'progress',
172	        data: JSON.stringify({ phase: 'loading_messages', message: 'Loading messages...' }),
173	      });
174	
175	      const result = await opts.analysisFn(session, messages, {
176	        signal: abortSignal,
177	        onProgress: (progress) => {
178	          const message = opts.progressMessage(progress);
179	          void stream.writeSSE({
180	            event: 'progress',
181	            data: JSON.stringify({ ...progress, message }),
182	          }).catch(() => {});
183	        },
184	      });
185	
186	      const baseProperties: Record<string, unknown> = {
187	        type: opts.analysisType,
188	        llm_provider: llmConfig?.provider,
189	        llm_model: llmConfig?.model,
190	        duration_ms: Date.now() - streamStart,
191	        success: result.success,
192	      };
193	
194	      if (!result.success) {
195	        const errorProperties: Record<string, unknown> = {
196	          ...baseProperties,
197	          error_type: result.error_type,
198	          error_message: result.error,
199	          response_preview: result.response_preview,
200	        };
201	        trackEvent('analysis_run', errorProperties);
202	        captureError(new Error(result.error ?? `${opts.analysisType} stream failed`), errorProperties);
203	        await stream.writeSSE({
204	          event: 'error',
205	          data: JSON.stringify({ error: result.error ?? `${opts.analysisType} analysis failed` }),
206	        });
207	      } else {
208	        trackEvent('analysis_run', baseProperties);
209	        opts.onSuccess?.(result);
210	
211	        // Compute cost from token usage for the SSE complete event.
212	        // The actual cost was already persisted to analysis_usage by the analysis function.
213	        // This includes it in the SSE payload so the dashboard can display it immediately
214	        // without an extra round-trip to GET /api/analysis/usage.
215	        const costUsd = result.usage && llmConfig
216	          ? calculateAnalysisCost(llmConfig.provider, llmConfig.model, {
217	              inputTokens: result.usage.inputTokens,
218	              outputTokens: result.usage.outputTokens,
219	              cacheCreationTokens: result.usage.cacheCreationTokens,
220	              cacheReadTokens: result.usage.cacheReadTokens,
221	            })
222	          : 0;
223	
224	        await stream.writeSSE({
225	          event: 'complete',
226	          data: JSON.stringify({
227	            success: true,
228	            insightCount: result.insights.length,
229	            tokenUsage: result.usage,
230	            costUsd,
231	            provider: llmConfig?.provider,
232	            model: llmConfig?.model,
233	          }),
234	        });
235	      }
236	    } catch (err) {
237	      const message = err instanceof Error ? err.message : 'Unknown error';
238	      // Normalize hyphens to underscores so 'prompt-quality_stream' becomes
239	      // 'prompt_quality_stream' — matching the original per-handler telemetry strings.
240	      const telemetryType = opts.analysisType.replace(/-/g, '_');
241	      captureError(err, {
242	        type: `${telemetryType}_stream`,
243	        llm_provider: llmConfig?.provider,
244	        llm_model: llmConfig?.model,
245	      });
246	      await stream.writeSSE({
247	        event: 'error',
248	        data: JSON.stringify({ error: message }),
249	      }).catch(() => {});
250	    }
251	  });
252	}
253	
254	// ─── Batch backfill SSE helper ────────────────────────────────────────────────
255	
256	/**
257	 * Options for streamBatchBackfill. The two backfill handlers (facets and PQ) share
258	 * the same loop structure but differ in how they check for existing work and which
259	 * analysis function they call.
260	 */
261	export interface StreamBatchBackfillOptions {
262	  /**
263	   * Returns true if the session should be skipped (work already done).
264	   * Only called when force=false; callers implement the appropriate SQL check.
265	   */
266	  shouldSkip: (sessionId: string) => boolean;
267	  /**
268	   * The analysis function to run for each session. Receives the loaded session,
269	   * its messages, and an AbortSignal. Returns a result with a success boolean.
270	   */
271	  analysisFn: (
272	    session: SessionData,
273	    messages: SQLiteMessageRow[],
274	    options: { signal: AbortSignal },
275	  ) => Promise<{ success: boolean; error?: string }>;
276	}
277	
278	/**
279	 * Shared SSE lifecycle for batch backfill endpoints (facets backfill and PQ backfill).
280	 * Iterates sessionIds one-by-one, streaming per-session progress events and a final
281	 * complete event. Preserves the exact SSE payload shapes the dashboard expects:
282	 *   progress → { completed, failed, total, currentSessionId, error? }
283	 *   complete → { completed, failed, total }
284	 *
285	 * The caller is responsible for request body validation (sessionIds array present,
286	 * length ≤ MAX_BACKFILL_SESSIONS) before calling this helper.
287	 */
288	export function streamBatchBackfill(
289	  c: Context,
290	  sessionIds: string[],
291	  force: boolean,
292	  opts: StreamBatchBackfillOptions,
293	): ReturnType<typeof streamSSE> {
294	  const db = getDb();
295	
296	  return streamSSE(c, async (stream) => {
297	    const abortSignal = c.req.raw.signal;
298	    let completed = 0;
299	    let failed = 0;
300	    const total = sessionIds.length;
301	
302	    for (const sessionId of sessionIds) {
303	      if (abortSignal.aborted) break;
304	
305	      const session = loadSessionForAnalysis(db, sessionId);
306	
307	      if (!session) {
308	        failed++;
309	        await stream.writeSSE({
310	          event: 'progress',
311	          data: JSON.stringify({ completed, failed, total, currentSessionId: sessionId }),
312	        });
313	        continue;
314	      }
315	
316	      // Skip sessions that already have work done unless force=true.
317	      if (!force && opts.shouldSkip(sessionId)) {
318	        completed++;
319	        await stream.writeSSE({
320	          event: 'progress',
321	          data: JSON.stringify({ completed, failed, total, currentSessionId: sessionId }),
322	        });
323	        continue;
324	      }
325	
326	      const messages = loadSessionMessages(db, sessionId);
327	      const result = await opts.analysisFn(session, messages, { signal: abortSignal });
328	
329	      if (result.success) {
330	        completed++;
331	      } else {
332	        failed++;
333	      }
334	
335	      await stream.writeSSE({
336	        event: 'progress',
337	        data: JSON.stringify({
338	          completed,
339	          failed,
340	          total,
341	          currentSessionId: sessionId,
342	          ...(result.success ? {} : { error: result.error }),
343	        }),
344	      });
345	    }
346	
347	    await stream.writeSSE({
348	      event: 'complete',
349	      data: JSON.stringify({ completed, failed, total }),
350	    });
351	  });
352	}
