154	/**
155	 * Parse a Node.js Error.stack into PostHog-compatible stack frames.
156	 * Returns frames in caller-first order (PostHog/Sentry convention).
157	 */
158	function parseStackFrames(stack: string): Array<{
159	  filename: string;
160	  lineno: number;
161	  colno: number;
162	  function: string;
163	  in_app: boolean;
164	}> {
165	  const framePattern = /at\s+(?:(.+?)\s+\()?(.*?):(\d+):(\d+)\)?/g;
166	  const frames: Array<{
167	    filename: string;
168	    lineno: number;
169	    colno: number;
170	    function: string;
171	    in_app: boolean;
172	  }> = [];
173	
174	  let match;
175	  while ((match = framePattern.exec(stack)) !== null) {
176	    const filename = match[2].replace(/^file:\/\//, '');
177	    frames.push({
178	      filename,
179	      lineno: parseInt(match[3], 10),
180	      colno: parseInt(match[4], 10),
181	      function: match[1] || '<anonymous>',
182	      in_app: !filename.includes('node_modules') && !filename.startsWith('node:'),
183	    });
184	  }
185	
186	  return frames;
187	}
